1	const fs = require('fs');
2	const { Document, Packer, Paragraph, TextRun, HeadingLevel, Table, TableRow, TableCell, WidthType, BorderStyle, ShadingType, PageBreak } = require('docx');
3	
4	// Load data from JSON
5	const data = JSON.parse(fs.readFileSync(__dirname + '/p0_analysis_data.json', 'utf8'));
6	
7	// Helpers
