56	  para('')
57	);
58	
59	// Priority summary
60	children.push(heading('执行优先级概览', 1));
61	const pLevels = [
62	  { title: '🔴 第一梯队：今天必须处理（2人）', data: data.summary.urgent },
63	  { title: '🟡 第二梯队：48h内处理（3人）', data: data.summary.high },
